function makeSpec(spec) {
  return {
    ...BASE_CONFIG,
    ...spec,
    config: {
      ...BASE_CONFIG.config,
      ...(spec.config || {})
    }
  };
}

function showChartError(targetId, message) {
  const target = document.getElementById(targetId);
  if (!target) return;
  target.innerHTML = `
    <div class="error-box">
      <strong>Chart failed to render:</strong> ${targetId}<br>
      ${message}
    </div>
  `;
}

function renderChart(targetId, spec) {
  vegaEmbed(`#${targetId}`, spec, { actions: false, renderer: "svg" })
    .then(() => console.log(`${targetId} rendered successfully`))
    .catch((error) => {
      console.error(`Error rendering ${targetId}:`, error);
      showChartError(targetId, "Open the browser console to inspect the Vega-Lite error.");
    });
}

function setLastModified() {
  const target = document.getElementById("last-modified");
  if (!target) return;
  // document.lastModified is unreliable on the filesystem (always returns
  // the current time). We display it only when served over HTTP, where the
  // browser receives an accurate Last-Modified header.
  const modified = new Date(document.lastModified);
  const isFilesystem = modified.toDateString() === new Date().toDateString()
    && window.location.protocol === "file:";
  target.textContent = isFilesystem
    ? ""
    : modified.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" });
}

/* fetchWithTimeout wraps fetch() so a single slow or missing file
   doesn't leave the whole Promise.all hanging indefinitely. */
function fetchWithTimeout(url, timeoutMs = 10000) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  return fetch(url, { signal: controller.signal })
    .finally(() => clearTimeout(timer));
}

async function loadCSV(path) {
  const response = await fetchWithTimeout(path);
  if (!response.ok) {
    throw new Error(`Failed to load CSV: ${path} (${response.status})`);
  }
  const text = await response.text();
  return vega.read(text, { type: "csv", parse: "auto" });
}

/* =========================
   STATE NAME NORMALISATION
   ========================= */
function canonicalStateName(name) {
  if (!name) return name;
  const cleaned = String(name).trim();
  const key = cleaned.toLowerCase().replace(/[^a-z]/g, "");

  const aliasMap = {
    penang:                              "Penang",
    pulaupinang:                         "Penang",
    ppinang:                             "Penang",

    kualalumpur:                         "Kuala Lumpur",
    wpkualalumpur:                       "Kuala Lumpur",
    wilayahpersekutuankualalumpur:       "Kuala Lumpur",

    putrajaya:                           "Putrajaya",
    wpputrajaya:                         "Putrajaya",
    wilayahpersekutuanputrajaya:         "Putrajaya",

    labuan:                              "Labuan",
    wplabuan:                            "Labuan",
    wilayahpersekutuanlabuan:            "Labuan"
  };

  return aliasMap[key] || cleaned;
}

/* Reads the canonical state name from a GeoJSON / TopoJSON feature.
   The TopoJSON we embed uses properties.Name, but we also support
   common alternative field names from external GeoJSON sources. */
function getGeoFeatureName(feature) {
  return (
    feature?.properties?.Name      ||
    feature?.properties?.shapeName ||
    feature?.properties?.name      ||
    feature?.properties?.NAME_1    ||
    feature?.properties?.state     ||
    ""
  );
}

function formatLegendNumber(value) {
  return Math.round(value).toLocaleString("en-US");
}

function pickSpacedColors(palette, n) {
  if (n <= 0) return [];
  if (n === 1) return [palette[palette.length - 1]];
  return Array.from({ length: n }, (_, i) => {
    const idx = Math.round((i * (palette.length - 1)) / (n - 1));
    return palette[idx];
  });
}

function buildFixedIntervalClasses(rows, fieldName, step = 500000, start = 0, palette = MAP_PALETTE) {
  const values = rows
    .map((d) => +d[fieldName])
    .filter((v) => Number.isFinite(v));

  if (!values.length) {
    return { rows: [], labels: [], colors: [] };
  }

  const max = Math.max(...values);
  const binCount = Math.max(1, Math.ceil((max - start + 1) / step));

  const bins = Array.from({ length: binCount }, (_, i) => {
    const lower = start + i * step;
    const upper = lower + step - 1;
    return {
      lower,
      upper,
      label: `${formatLegendNumber(lower)} – ${formatLegendNumber(upper)}`
    };
  });

  const classifiedRows = rows.map((d) => {
    const value = +d[fieldName];
    const rawIndex = Math.floor((value - start) / step);
    const intervalIndex = Math.min(Math.max(rawIndex, 0), bins.length - 1);
    return {
      ...d,
      interval_index: intervalIndex,
      interval_label: bins[intervalIndex].label
    };
  });

  const usedBins   = [...new Set(classifiedRows.map((d) => d.interval_index))].sort((a, b) => a - b);
  const usedLabels = usedBins.map((i) => bins[i].label);
  const usedColors = pickSpacedColors(palette, usedLabels.length);

  return { rows: classifiedRows, labels: usedLabels, colors: usedColors };
}

/* =========================
   DATA TRANSFORMS
   ========================= */

/* FIX: index each quarter against the matching 2019 quarter, not against
   the average of all four 2019 quarters.  The old approach made Q1 and Q3
   (lower-volume quarters) appear above / below 100 even within 2019 itself. */
function computeRecoveryIndex(quarterly) {
  const baselineMap = new Map(
    quarterly
      .filter((d) => d.year === 2019)
      .map((d) => [d.quarter_num, d.arrivals])
  );

  return quarterly.map((d) => ({
    ...d,
    recovery_index: baselineMap.has(d.quarter_num)
      ? (d.arrivals / baselineMap.get(d.quarter_num)) * 100
      : null
  }));
}

function computeExpenditureShareChange(expenditure) {
  const years    = [2000, 2020];
  const filtered = expenditure.filter((d) => years.includes(d.year));
  const totals   = {};
  filtered.forEach((d) => {
    totals[d.year] = (totals[d.year] || 0) + d.expenditure_rm_million;
  });
  return filtered.map((d) => ({
    ...d,
    share: d.expenditure_rm_million / totals[d.year]
  }));
}

function computeExpenditureDumbbellRows(expenditureShareChange) {
  const grouped = new Map();
  expenditureShareChange.forEach((d) => {
    const key = d.product_short;
    if (!grouped.has(key)) {
      grouped.set(key, { product: d.product, product_short: d.product_short, share_2000: null, share_2020: null });
    }
    const row = grouped.get(key);
    if (+d.year === 2000) row.share_2000 = +d.share;
    if (+d.year === 2020) row.share_2020 = +d.share;
  });

  return Array.from(grouped.values())
    .filter((d) => Number.isFinite(d.share_2000) && Number.isFinite(d.share_2020))
    .map((d) => {
      const deltaPercent = (d.share_2020 - d.share_2000) * 100;
      return {
        ...d,
        delta_percent: deltaPercent,
        delta_abs:     Math.abs(deltaPercent),
        label_anchor:  Math.max(d.share_2000, d.share_2020) + 0.015,
        change_label:
          deltaPercent > 0 ? `▲ ${deltaPercent.toFixed(1)}%`
          : deltaPercent < 0 ? `▼ ${Math.abs(deltaPercent).toFixed(1)}%`
          : "0.0%"
      };
    })
    .sort((a, b) => b.delta_abs - a.delta_abs);
}

function computeBumpRows(stateCore) {
  const selected = stateCore.filter((d) => BUMP_STATES.includes(d.state));
  const years    = [...new Set(selected.map((d) => d.year))].sort((a, b) => a - b);
  const rankedRows = [];

  years.forEach((year) => {
    const rows = selected
      .filter((d) => d.year === year)
      .sort((a, b) => b.international_hotel_guests - a.international_hotel_guests)
      .map((d, i) => ({ ...d, rank: i + 1 }));
    rankedRows.push(...rows);
  });

  const finalYear = Math.max(...years);
  const labelRows = rankedRows
    .filter((d) => d.year === finalYear)
    .map((d) => ({ ...d, label_x: finalYear + 0.4 }));

  return { rows: rankedRows, labels: labelRows, years };
}

function computeStateRecoveryRows(stateCore) {
  const byState = new Map();

  stateCore.forEach((d) => {
    const state = canonicalStateName(d.state);
    if (!byState.has(state)) {
      byState.set(state, { state, guests_2019: null, guests_2022: null });
    }
    const row = byState.get(state);
    if (+d.year === 2019) row.guests_2019 = +d.international_hotel_guests;
    if (+d.year === 2022) row.guests_2022 = +d.international_hotel_guests;
  });

  return Array.from(byState.values())
    .filter((d) => Number.isFinite(d.guests_2019) && d.guests_2019 > 0 && Number.isFinite(d.guests_2022))
    .map((d) => ({
      ...d,
      recovery_pct: (d.guests_2022 / d.guests_2019) * 100,
      label_x: (d.guests_2022 / d.guests_2019) * 100 + 2
    }))
    .sort((a, b) => b.recovery_pct - a.recovery_pct);
}

function computeExpenditureWaterfallRows(expenditure) {
  const grouped = new Map();

  expenditure.forEach((d) => {
    const key = d.product_short;
    if (!grouped.has(key)) {
      grouped.set(key, {
        product_short: key,
        value_2000: 0,
        value_2020: 0
      });
    }
    const row = grouped.get(key);
    if (+d.year === 2000) row.value_2000 = +d.expenditure_rm_million;
    if (+d.year === 2020) row.value_2020 = +d.expenditure_rm_million;
  });

  const contributions = Array.from(grouped.values())
    .map((d) => ({
      product_short: d.product_short,
      change_rm_million: d.value_2020 - d.value_2000
    }))
    .filter((d) => Number.isFinite(d.change_rm_million))
    .sort((a, b) => Math.abs(b.change_rm_million) - Math.abs(a.change_rm_million));

  let cumulative = 0;
  const rows = contributions.map((d) => {
    const start = cumulative;
    const end = cumulative + d.change_rm_million;
    cumulative = end;
    return {
      category: d.product_short,
      start,
      end,
      amount: d.change_rm_million,
      label_y: d.change_rm_million >= 0 ? end : start,
      direction: d.change_rm_million >= 0 ? 'Increase' : 'Decrease',
      amount_label: `${d.change_rm_million >= 0 ? '+' : '−'}RM ${Math.abs(d.change_rm_million).toFixed(0)}m`
    };
  });

  rows.push({
    category: 'Net change',
    start: 0,
    end: cumulative,
    amount: cumulative,
    label_y: cumulative,
    direction: 'Total',
    amount_label: `${cumulative >= 0 ? '+' : '−'}RM ${Math.abs(cumulative).toFixed(0)}m`
  });

  return rows;
}

